 45→        taskRepository.deleteAll();
 46→        userRepository.deleteAll();
 47→
 48→        RegisterRequest reg = new RegisterRequest();
 49→        reg.setUsername("stateuser");
 50→        reg.setPassword("password123");
 51→        reg.setDisplayName("State User");
 52→
 53→        mockMvc.perform(post("/api/auth/register")
 54→                        .contentType(MediaType.APPLICATION_JSON)
 55→                        .content(objectMapper.writeValueAsString(reg)))
 56→                .andExpect(status().isCreated());
 57→
 58→        LoginRequest login = new LoginRequest();
 59→        login.setUsername("stateuser");
 60→        login.setPassword("password123");
 61→
 62→        MvcResult loginResult = mockMvc.perform(post("/api/auth/login")
 63→                        .contentType(MediaType.APPLICATION_JSON)
 64→                        .content(objectMapper.writeValueAsString(login)))
 65→                .andExpect(status().isOk())
 66→                .andReturn();
 67→
 68→        JsonNode loginJson = objectMapper.readTree(loginResult.getResponse().getContentAsString());
 69→        authToken = loginJson.get("token").asText();
 70→    }
 71→
 72→    // ========== Helper Methods ==========
 73→
 74→    private Long createTask(String title) throws Exception {
 75→        String json = "{\"title\":\"" + title + "\"}";
 76→        MvcResult result = mockMvc.perform(post("/api/tasks")
 77→                        .header("Authorization", "Bearer " + authToken)
 78→                        .contentType(MediaType.APPLICATION_JSON)
 79→                        .content(json))
 80→                .andExpect(status().isCreated())
 81→                .andReturn();
 82→        return objectMapper.readTree(result.getResponse().getContentAsString()).get("id").asLong();
 83→    }
 84→
 85→    private MvcResult changeStatus(Long taskId, String targetStatus) throws Exception {
 86→        String json = "{\"status\":\"" + targetStatus + "\"}";
 87→        return mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
 88→                        .header("Authorization", "Bearer " + authToken)
 89→                        .contentType(MediaType.APPLICATION_JSON)
 90→                        .content(json))
 91→                .andReturn();
 92→    }
 93→
 94→    private void changeStatusExpect200(Long taskId, String targetStatus) throws Exception {
 95→        String json = "{\"status\":\"" + targetStatus + "\"}";
 96→        mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
 97→                        .header("Authorization", "Bearer " + authToken)
 98→                        .contentType(MediaType.APPLICATION_JSON)
 99→                        .content(json))
100→                .andExpect(status().isOk());
101→    }
