package com.taskflow.service;

import com.taskflow.entity.Task.TaskStatus;
import org.springframework.stereotype.Component;

import java.util.Collections;
import java.util.EnumMap;
import java.util.List;
import java.util.Map;

@Component
public class TaskStateMachine {

    private static final Map<TaskStatus, List<TaskStatus>> TRANSITIONS;

    static {
        Map<TaskStatus, List<TaskStatus>> map = new EnumMap<>(TaskStatus.class);
        map.put(TaskStatus.TODO, List.of(TaskStatus.IN_PROGRESS));
        map.put(TaskStatus.IN_PROGRESS, List.of(TaskStatus.TODO, TaskStatus.DONE));
        map.put(TaskStatus.DONE, List.of(TaskStatus.CLOSED));
        map.put(TaskStatus.CLOSED, Collections.emptyList());
        TRANSITIONS = Collections.unmodifiableMap(map);
    }

    public boolean canTransition(TaskStatus from, TaskStatus to) {
        return TRANSITIONS.getOrDefault(from, Collections.emptyList()).contains(to);
    }

    public List<TaskStatus> getAvailableTransitions(TaskStatus status) {
        return TRANSITIONS.getOrDefault(status, Collections.emptyList());
    }
}

